import{_ as i,c as a,o as t,a5 as n,aZ as o}from"./chunks/framework.Dm71djiW.js";const u=JSON.parse('{"title":"Version Change Log v2025.0","description":"","frontmatter":{"title":"Version Change Log v2025.0"},"headers":[],"relativePath":"docs/changelog-v2025.0.x.md","filePath":"docs/changelog-v2025.0.x.md","lastUpdated":1772156779000}'),r={name:"docs/changelog-v2025.0.x.md"};function l(s,e,d,c,p,m){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="liii-stem-v2025-0-version-change-log" tabindex="-1">Liii STEM v2025.0 Version Change Log <a class="header-anchor" href="#liii-stem-v2025-0-version-change-log" aria-label="Permalink to “Liii STEM v2025.0 Version Change Log”">​</a></h1><h2 id="⭐️-new-features-and-highlights" tabindex="-1">⭐️ New Features and Highlights <a class="header-anchor" href="#⭐️-new-features-and-highlights" aria-label="Permalink to “⭐️ New Features and Highlights”">​</a></h2><ol><li><strong>New Liii theme enabled by default</strong>: a modern UI refresh and smoother interactions.</li><li><strong>Stronger AI (LLM + VLM)</strong>: support for more models (Kimi K2, Qwen series, MiniMax, etc.), plus image Q&amp;A, handwritten formula recognition, and multi-turn follow-ups.</li><li><strong>Configurable model params &amp; networking</strong>: tune <code>temperature</code> and configure a <code>proxy</code> for flexible usage.</li><li><strong>Better math typesetting &amp; LaTeX export</strong>: improved multi-integral parsing, more standard LaTeX output, and better formula paste compatibility.</li><li><strong>Improved cross-platform experience</strong>: Ubuntu packages, no manual Pandoc install on macOS for LLM chat, and no terminal pop-ups on Windows when calling models.</li><li><strong>Efficiency &amp; stability improvements</strong>: new tab shortcuts, faster plugin loading, and fixes for images/HTML/file-name edge cases.</li></ol><h2 id="🌟-summary" tabindex="-1">🌟 Summary <a class="header-anchor" href="#🌟-summary" aria-label="Permalink to “🌟 Summary”">​</a></h2><p>Liii STEM v2025.0 is a broad upgrade across UI design, multi-model and multi-modal AI, professional math typesetting and LaTeX export, plus meaningful cross-platform and stability improvements.</p><h2 id="🔧-changelog" tabindex="-1">🔧 Changelog <a class="header-anchor" href="#🔧-changelog" aria-label="Permalink to “🔧 Changelog”">​</a></h2><h3 id="liii-stem-v2025-0-12-2025-07-16" tabindex="-1">Liii STEM v2025.0.12 (2025.07.16) <a class="header-anchor" href="#liii-stem-v2025-0-12-2025-07-16" aria-label="Permalink to “Liii STEM v2025.0.12 (2025.07.16)”">​</a></h3><h3 id="update-content" tabindex="-1">Update Content <a class="header-anchor" href="#update-content" aria-label="Permalink to “Update Content”">​</a></h3><ol><li><p><strong>Interface and Function Optimization</strong></p><ul><li>Default enabled newly designed <strong>Liii Theme</strong>, providing more modern visual experience</li><li>&quot;Tools-&gt;Keyboard-&gt;Show Keyboard Keys&quot; supports Windows system</li><li><strong>LaTeX Export Improvement</strong>: Default disabled macro customizations with <code>tm</code> prefix, output more standard LaTeX code</li></ul></li><li><p><strong>Large Language Model Function Enhancement</strong></p><ul><li>Added support for <strong>SiliconFlow Kimi K2 Model</strong>, expanding dialogue capabilities</li><li>Improved mathematical symbol support: Optimized parsing and rendering of <code>\\oiint</code> (loop double integral), <code>\\iiint</code> (triple integral), <code>\\oint</code> (loop integral)</li><li><strong>macOS Convenience</strong>: No need to manually install Pandoc to use large language model dialogue</li><li><strong>Windows Experience Fix</strong>: Resolved issue of black terminal window popping up when calling large language models</li></ul></li></ol><p>Link: <a href="./../library/liii-stem-guide/changelog-v2025.0.12.html">Key Points Overview</a></p><h3 id="liii-stem-v2025-0-11-2025-06-29" tabindex="-1">Liii STEM v2025.0.11 (2025.06.29) <a class="header-anchor" href="#liii-stem-v2025-0-11-2025-06-29" aria-label="Permalink to “Liii STEM v2025.0.11 (2025.06.29)”">​</a></h3><h3 id="update-content-1" tabindex="-1">Update Content <a class="header-anchor" href="#update-content-1" aria-label="Permalink to “Update Content”">​</a></h3><ol><li>Comprehensively improved user interface theme visual effects, added Liii user interface theme (users can switch themes in <code>Edit</code> -&gt; <code>Preferences</code> -&gt; <code>User Interface Theme</code> -&gt; <code>Liii</code>)</li><li>Fixed defect where VLM could not ask follow-up questions</li><li>Fixed defect where switching tabs would return to document beginning instead of last mouse hover position</li><li>Now supports Ctrl/Cmd + number (1-6) to switch tabs</li><li>Now supports Ctrl/Cmd + T to add new tabs</li><li>LLM plugin added support for models:</li></ol><ul><li>Qwen2.5-VL-7B-Instruct (supports VLM, small and fast, can be used for formula recognition, recommended prompt &quot;recognize but don&#39;t reason&quot;)</li><li>Qwen2.5-VL-32B (supports VLM)</li><li>Qwen2.5-VL-72B-Instruct (supports VLM)</li><li>Qwen3-235B-A22B</li><li>MiniMax-M1-80k</li></ul><h3 id="liii-stem-v2025-0-10-2025-06-07" tabindex="-1">Liii STEM v2025.0.10 (2025.06.07) <a class="header-anchor" href="#liii-stem-v2025-0-10-2025-06-07" aria-label="Permalink to “Liii STEM v2025.0.10 (2025.06.07)”">​</a></h3><h3 id="update-content-2" tabindex="-1">Update Content <a class="header-anchor" href="#update-content-2" aria-label="Permalink to “Update Content”">​</a></h3><ol><li>Fixed defect where VLM couldn&#39;t load large images, can display as shown in the image effect</li><li>Mathematical environment <code>*</code> now prioritizes displaying <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>×</mo></mrow><annotation encoding="application/x-tex">\\times</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6667em;vertical-align:-0.0833em;"></span><span class="mord">×</span></span></span></span></li><li>Improved plugin loading method, significantly optimized performance</li></ol><p>Attachment: <a href="/demo_vlm.tmu" download>VLM Function Example</a></p><p><br><br><br><br><br></p><h3 id="liii-stem-v2025-0-8-2025-04-25" tabindex="-1">Liii STEM v2025.0.8 (2025.04.25) <a class="header-anchor" href="#liii-stem-v2025-0-8-2025-04-25" aria-label="Permalink to “Liii STEM v2025.0.8 (2025.04.25)”">​</a></h3><h3 id="update-content-3" tabindex="-1">Update Content <a class="header-anchor" href="#update-content-3" aria-label="Permalink to “Update Content”">​</a></h3><ol><li>Ubuntu 22.04 installation package (seed user zhengyq, Zeyu Dong requirement)</li><li>Improved error handling to enhance LLM plugin user experience</li><li>Supports VLM, enabling image AI Q&amp;A, handwritten formula recognition, etc. (almost all users require)</li><li>Fixed Definition/定义 environment to upright font (seed user iamspuerboy, Zeyu Dong, etc. requirement)</li><li>Added Assumption/假设 environment (seed user HaggittLi, Cauchy, etc. requirement)</li><li>Fixed defect where images couldn&#39;t be imported (discovered by sprouting user Ziegward)</li></ol><p><br><br><br><br><br></p><h3 id="liii-stem-v2025-0-7-2025-04-16" tabindex="-1">Liii STEM v2025.0.7 (2025.04.16) <a class="header-anchor" href="#liii-stem-v2025-0-7-2025-04-16" aria-label="Permalink to “Liii STEM v2025.0.7 (2025.04.16)”">​</a></h3><h3 id="update-content-4" tabindex="-1">Update Content <a class="header-anchor" href="#update-content-4" aria-label="Permalink to “Update Content”">​</a></h3><h4 id="function-fixes" tabindex="-1">Function Fixes <a class="header-anchor" href="#function-fixes" aria-label="Permalink to “Function Fixes”">​</a></h4><ol><li>Fixed format exception issues when importing or pasting HTML content</li><li>Fixed issue where file names containing asterisk(*) characters caused software unresponsiveness <ul><li>Software will now prohibit creating or opening file names containing asterisks</li></ul></li></ol><h4 id="llm-function-enhancement" tabindex="-1">LLM Function Enhancement <a class="header-anchor" href="#llm-function-enhancement" aria-label="Permalink to “LLM Function Enhancement”">​</a></h4><ol><li>Added proxy configuration support <ul><li>Added proxy parameter for configuring network proxy</li></ul></li><li>Added model parameter adjustment <ul><li>Supports adjusting temperature parameter to control output randomness</li></ul></li><li>Extended model support <ul><li>Added support for OpenAI series large language models</li></ul></li></ol><p><br><br><br><br><br></p><h3 id="liii-stem-v2025-0-6-2025-03-26" tabindex="-1">Liii STEM v2025.0.6 (2025.03.26) <a class="header-anchor" href="#liii-stem-v2025-0-6-2025-03-26" aria-label="Permalink to “Liii STEM v2025.0.6 (2025.03.26)”">​</a></h3><h3 id="update-content-5" tabindex="-1">Update Content <a class="header-anchor" href="#update-content-5" aria-label="Permalink to “Update Content”">​</a></h3><ol><li>Supports Zhihu and Doubao mathematical formula pasting</li><li>Now when modifying interface language, software automatically restarts to avoid software crash</li><li>Supports exporting formatted Mogan Scheme</li><li>Upgraded to Goldfish Scheme v17.11.9</li></ol><h2 id="👏-join-us" tabindex="-1">👏 Join Us <a class="header-anchor" href="#👏-join-us" aria-label="Permalink to “👏 Join Us”">​</a></h2><p>Scan the QR code to join the Mogan community QQ group or join the Discord group to connect with like-minded individuals online and get the latest news about Liii STEM.</p><ul><li>Liii STEM Official Website: <a href="https://liiistem.cn/" target="_blank" rel="noreferrer">https://liiistem.cn/</a></li><li>Mogan Community QQ Group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt/hpydluCE/cF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ==&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="noreferrer">934456971</a></li><li>Discord Group: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="noreferrer">https://discord.gg/Q7xARnAf8t</a></li></ul><p><img src="'+o+'" alt=""></p>',37)])])}const g=i(r,[["render",l]]);export{u as __pageData,g as default};
